import type { Flags } from './core';

// Approach A's selling point: TS stays the source of truth AND can emit a
// tailored minimal shell. Components are assembled from the resolved flags, so
// the ejected script only carries what that config needs. --yolo deletes every
// stage, so its script drops merge detection (is_merged) entirely.

const HEADER = `#!/usr/bin/env sh
# generated by 'git-harvest eject' -- regenerate, do not edit by hand
set -eu
base=$(git symbolic-ref refs/remotes/origin/HEAD | sed 's|refs/remotes/origin/||')
main_wt=$(git worktree list --porcelain | awk '/^worktree /{sub(/^worktree /,""); print; exit}')
cur_wt=$(cd "$(git rev-parse --show-toplevel)" && pwd -P)
cur_head=$(git symbolic-ref --short HEAD 2>/dev/null || echo "")`;

const IS_MERGED = `is_merged() {
  b=$1
  if git merge-base --is-ancestor "$b" "$base" 2>/dev/null; then return 0; fi
  mb=$(git merge-base "$base" "$b" 2>/dev/null) || return 1
  sq=$(git commit-tree "$b^{tree}" -p "$mb" -m _ 2>/dev/null) || return 1
  if git cherry "$base" "$sq" 2>/dev/null | grep -q '^+'; then return 1; fi
  return 0
}`;

const WT_HEADER = `git worktree list --porcelain | awk '/^worktree /{sub(/^worktree /,""); print}' | while IFS= read -r wt; do
  if [ "$wt" = "$main_wt" ]; then continue; fi
  wtc=$(cd "$wt" 2>/dev/null && pwd -P) || continue
  if [ "$wtc" = "$cur_wt" ]; then continue; fi
  br=$(git -C "$wt" symbolic-ref --short HEAD 2>/dev/null || echo "")
  if [ "$br" = "$base" ]; then continue; fi`;

function worktreeLoop(flags: Flags): string {
  if (flags.yolo) {
    return `${WT_HEADER}
  if git worktree remove --force "$wt" 2>/dev/null; then echo "removed worktree: $wt"; fi
done`;
  }

  const committed = flags.worktree === 'committed'
    ? `\n  elif git worktree remove --force "$wt" 2>/dev/null; then echo "removed worktree: $wt"`
    : '';

  return `${WT_HEADER}
  if [ -z "$br" ]; then continue; fi
  if is_merged "$br"; then
    if git worktree remove "$wt" 2>/dev/null; then echo "removed worktree: $wt"; fi${committed}
  fi
done`;
}

function branchLoop(flags: Flags): string {
  const cond = flags.yolo ? 'true' : 'is_merged "$b"';

  return `git branch --format='%(refname:short)' | while IFS= read -r b; do
  if [ "$b" = "$base" ]; then continue; fi
  if [ "$b" = "$cur_head" ]; then continue; fi
  if ${cond}; then
    if git branch -D "$b" >/dev/null 2>&1; then echo "removed branch: $b"; fi
  fi
done`;
}

export function eject(flags: Flags): string {
  const blocks = [HEADER];

  if (!flags.yolo) blocks.push(IS_MERGED);
  blocks.push(worktreeLoop(flags), branchLoop(flags));

  return `${blocks.join('\n\n')}\n`;
}
